import azure.functions as func
import logging
import os
import re
from azure.storage.blob import BlobServiceClient
from azure.identity import DefaultAzureCredential


def validate_blob_path(blob_path: str) -> bool:
    """Validate blob path to prevent path traversal and injection attacks."""
    if not blob_path:
        return False
    
    # Reject path traversal attempts
    if '..' in blob_path:
        return False
    
    # Reject absolute paths
    if blob_path.startswith('/') or blob_path.startswith('\\'):
        return False
    
    # Reject backslashes (normalize to forward slashes only)
    if '\\' in blob_path:
        return False
    
    # Only allow alphanumeric, hyphens, underscores, dots, and forward slashes
    if not re.match(r'^[a-zA-Z0-9\-_./]+$', blob_path):
        return False
    
    # Reject paths with double slashes
    if '//' in blob_path:
        return False
    
    # Reject hidden files/directories (starting with dot)
    path_parts = blob_path.split('/')
    for part in path_parts:
        if part.startswith('.'):
            return False
        if not part:
            return False
    
    # Enforce maximum path length
    if len(blob_path) > 1024:
        return False
    
    return True


ALLOWED_CONTAINERS = None

def get_allowed_containers() -> set:
    """Load allowed container names from environment configuration."""
    global ALLOWED_CONTAINERS
    if ALLOWED_CONTAINERS is None:
        containers_env = os.environ.get("ALLOWED_BLOB_CONTAINERS", "")
        ALLOWED_CONTAINERS = {c.strip() for c in containers_env.split(",") if c.strip()}
    return ALLOWED_CONTAINERS


ALLOWED_EXTENSIONS = {
    '.txt', '.json', '.csv', '.xml', '.pdf', '.png', '.jpg', '.jpeg',
    '.gif', '.svg', '.html', '.css', '.js', '.md', '.yaml', '.yml'
}


def validate_file_extension(blob_path: str) -> bool:
    """Validate that the file extension is in the allowlist."""
    _, ext = os.path.splitext(blob_path)
    if not ext:
        return False
    return ext.lower() in ALLOWED_EXTENSIONS


CONTENT_TYPE_MAP = {
    '.txt': 'text/plain',
    '.json': 'application/json',
    '.csv': 'text/csv',
    '.xml': 'application/xml',
    '.pdf': 'application/pdf',
    '.png': 'image/png',
    '.jpg': 'image/jpeg',
    '.jpeg': 'image/jpeg',
    '.gif': 'image/gif',
    '.svg': 'image/svg+xml',
    '.html': 'text/html',
    '.css': 'text/css',
    '.js': 'application/javascript',
    '.md': 'text/markdown',
    '.yaml': 'application/x-yaml',
    '.yml': 'application/x-yaml',
}


def get_content_type(blob_path: str) -> str:
    """Determine content type based on file extension."""
    _, ext = os.path.splitext(blob_path)
    return CONTENT_TYPE_MAP.get(ext.lower(), 'application/octet-stream')


MAX_BLOB_SIZE = 50 * 1024 * 1024  # 50 MB


app = func.FunctionApp()


@app.route(route="files", auth_level=func.AuthLevel.FUNCTION, methods=["GET"])
def serve_file(req: func.HttpRequest) -> func.HttpResponse:
    """
    HTTP-triggered Azure Function to serve files from Blob Storage.
    
    Query Parameters:
        container: The blob container name
        path: The blob path (supports nested paths like 'folder/subfolder/file.txt')
    """
    # Extract and validate query parameters
    container_name = req.params.get('container')
    blob_path = req.params.get('path')

    if not container_name or not blob_path:
        return func.HttpResponse(
            '{"error": "Missing required query parameters: container, path"}',
            status_code=400,
            mimetype="application/json"
        )

    # Validate container name (alphanumeric and hyphens only, 3-63 chars per Azure rules)
    if not re.match(r'^[a-z0-9][a-z0-9\-]{1,61}[a-z0-9]$', container_name):
        logging.warning("Invalid container name requested: length=%d", len(container_name))
        return func.HttpResponse(
            '{"error": "Invalid container name"}',
            status_code=400,
            mimetype="application/json"
        )

    # Check container against allowlist
    allowed_containers = get_allowed_containers()
    if allowed_containers and container_name not in allowed_containers:
        logging.warning("Access denied to container (not in allowlist)")
        return func.HttpResponse(
            '{"error": "Access denied"}',
            status_code=403,
            mimetype="application/json"
        )

    # Validate blob path
    if not validate_blob_path(blob_path):
        logging.warning("Invalid blob path requested")
        return func.HttpResponse(
            '{"error": "Invalid blob path"}',
            status_code=400,
            mimetype="application/json"
        )

    # Validate file extension
    if not validate_file_extension(blob_path):
        logging.warning("Disallowed file extension requested")
        return func.HttpResponse(
            '{"error": "File type not allowed"}',
            status_code=403,
            mimetype="application/json"
        )

    # Normalize the path to prevent any remaining traversal
    normalized_path = os.path.normpath(blob_path).replace('\\', '/')
    if normalized_path != blob_path:
        logging.warning("Blob path normalization mismatch detected")
        return func.HttpResponse(
            '{"error": "Invalid blob path"}',
            status_code=400,
            mimetype="application/json"
        )

    try:
        # Use managed identity (DefaultAzureCredential) instead of connection strings
        # Falls back to environment-based auth for local development
        storage_account_url = os.environ.get("STORAGE_ACCOUNT_URL")
        
        if not storage_account_url:
            logging.error("STORAGE_ACCOUNT_URL environment variable not configured")
            return func.HttpResponse(
                '{"error": "Service configuration error"}',
                status_code=500,
                mimetype="application/json"
            )

        # Validate storage account URL format
        if not re.match(r'^https://[a-z0-9]+\.blob\.core\.windows\.net/?$', storage_account_url):
            logging.error("Invalid STORAGE_ACCOUNT_URL format")
            return func.HttpResponse(
                '{"error": "Service configuration error"}',
                status_code=500,
                mimetype="application/json"
            )

        credential = DefaultAzureCredential()
        blob_service_client = BlobServiceClient(
            account_url=storage_account_url,
            credential=credential
        )

        blob_client = blob_service_client.get_blob_client(
            container=container_name,
            blob=normalized_path
        )

        # Check blob properties first to validate size before downloading
        blob_properties = blob_client.get_blob_properties()
        blob_size = blob_properties.size

        if blob_size > MAX_BLOB_SIZE:
            logging.warning(
                "Blob size exceeds maximum allowed: %d bytes",
                blob_size
            )
            return func.HttpResponse(
                '{"error": "File too large"}',
                status_code=413,
                mimetype="application/json"
            )

        # Download the blob content
        download_stream = blob_client.download_blob()
        blob_content = download_stream.readall()

        content_type = get_content_type(normalized_path)

        # Log successful access (without sensitive path details at INFO level)
        logging.info(
            "File served successfully from container=%s, size=%d bytes",
            container_name,
            len(blob_content)
        )

        return func.HttpResponse(
            body=blob_content,
            status_code=200,
            mimetype=content_type,
            headers={
                "X-Content-Type-Options": "nosniff",
                "Cache-Control": "private, max-age=300",
                "Content-Disposition": "inline",
            }
        )

    except Exception as e:
        error_type = type(e).__name__
        
        # Check for "not found" type errors
        if "BlobNotFound" in str(type(e).__mro__) or "ResourceNotFoundError" in error_type or "404" in str(e):
            logging.info("Blob not found in container=%s", container_name)
            return func.HttpResponse(
                '{"error": "File not found"}',
                status_code=404,
                mimetype="application/json"
            )

        if "AuthenticationError" in error_type or "AuthorizationError" in error_type:
            logging.error("Authentication/authorization error accessing blob storage")
            return func.HttpResponse(
                '{"error": "Service configuration error"}',
                status_code=500,
                mimetype="application/json"
            )

        # Log the error type but not the full message (may contain sensitive info)
        logging.error("Error serving file: %s", error_type)
        return func.HttpResponse(
            '{"error": "Internal server error"}',
            status_code=500,
            mimetype="application/json"
        )